:root {
  --card-bg: #1c1c2e;
  --card-border: #3a3a5c;
  --header-bg: #252540;
  --shop-name-color: #f0e6d3;
  --tagline-color: #9090b8;
  --badge-bg: #4caf82;
  --badge-color: #ffffff;
  --tab-bg: #2e2e4a;
  --tab-color: #9090b8;
  --tab-active-bg: #f0a500;
  --tab-active-color: #1c1c2e;
  --item-bg: #252540;
  --item-border: #3a3a5c;
  --featured-border: #f0a500;
  --label-cream-bg: #f5e6c8;
  --label-cream-text: #3a2a10;
  --label-gold-bg: #e8c84a;
  --label-gold-text: #3a2a10;
  --label-teal-bg: #4ab8c8;
  --label-teal-text: #0a2a30;
  --title-color: #f0e6d3;
  --artist-color: #9090b8;
  --year-color: #6868a0;
  --condition-mint-bg: #1e5c3a;
  --condition-mint-color: #4cdf9a;
  --condition-vg-bg: #4a3a10;
  --condition-vg-color: #f0c040;
  --condition-good-bg: #3a2a50;
  --condition-good-color: #b090e0;
  --price-color: #f0a500;
  --footer-bg: #252540;
  --footer-text: #6868a0;
  --btn-bg: #f0a500;
  --btn-color: #1c1c2e;
  --record-bg: #0a0a18;
  --record-inner-bg: #f0a500;
}

.shop-card {
  background: var(--card-bg);
  border: 2px solid var(--card-border);
  border-radius: 16px;
  width: 500px;
  overflow: hidden;
}

.shop-header {
  background: var(--header-bg);
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 14px 16px;
  border-bottom: 1px solid var(--card-border);
}

.shop-logo {
  flex-shrink: 0;
}

.record-icon {
  width: 40px;
  height: 40px;
  background: var(--record-bg);
  border-radius: 50%;
  border: 4px solid var(--card-border);
  display: flex;
  align-items: center;
  justify-content: center;
}

.record-inner {
  width: 10px;
  height: 10px;
  background: var(--record-inner-bg);
  border-radius: 50%;
}

.shop-title {
  display: flex;
  flex-direction: column;
  gap: 2px;
  flex: 1;
}

.shop-name {
  font-size: 18px;
  font-weight: 700;
  color: var(--shop-name-color);
  letter-spacing: 0.5px;
}

.shop-tagline {
  font-size: 11px;
  color: var(--tagline-color);
  font-weight: 400;
}

.shop-badge {
  background: var(--badge-bg);
  color: var(--badge-color);
  font-size: 11px;
  font-weight: 700;
  padding: 4px 10px;
  border-radius: 20px;
  letter-spacing: 1px;
}

.genre-tabs {
  display: flex;
  gap: 8px;
  padding: 12px 16px;
  border-bottom: 1px solid var(--card-border);
}

.tab {
  background: var(--tab-bg);
  color: var(--tab-color);
  font-size: 12px;
  font-weight: 600;
  padding: 5px 14px;
  border-radius: 20px;
  cursor: pointer;
}

.tab.active {
  background: var(--tab-active-bg);
  color: var(--tab-active-color);
}

.records-grid {
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding: 12px 16px;
}

.record-item {
  background: var(--item-bg);
  border: 1px solid var(--item-border);
  border-radius: 10px;
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 12px;
}

.record-item.featured {
  border-color: var(--featured-border);
}

.record-label {
  width: 48px;
  height: 48px;
  border-radius: 50%;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  padding: 4px;
}

.record-label.cream {
  background: var(--label-cream-bg);
}

.record-label.gold {
  background: var(--label-gold-bg);
}

.record-label.teal {
  background: var(--label-teal-bg);
}

.label-title {
  font-size: 7px;
  font-weight: 700;
  text-align: center;
  line-height: 1.2;
}

.record-label.cream .label-title,
.record-label.cream .label-artist {
  color: var(--label-cream-text);
}

.record-label.gold .label-title,
.record-label.gold .label-artist {
  color: var(--label-gold-text);
}

.record-label.teal .label-title,
.record-label.teal .label-artist {
  color: var(--label-teal-text);
}

.label-artist {
  font-size: 6px;
  font-weight: 500;
  text-align: center;
  line-height: 1.2;
}

.record-meta {
  display: flex;
  flex-direction: column;
  gap: 4px;
  flex: 1;
}

.label-title-text {
  font-size: 14px;
  font-weight: 600;
  color: var(--title-color);
}

.year {
  font-size: 13px;
  color: var(--year-color);
  font-weight: 500;
}

.condition {
  font-size: 11px;
  font-weight: 700;
  padding: 2px 8px;
  border-radius: 4px;
  align-self: flex-start;
}

.condition.mint {
  background: var(--condition-mint-bg);
  color: var(--condition-mint-color);
}

.condition.vg {
  background: var(--condition-vg-bg);
  color: var(--condition-vg-color);
}

.condition.good {
  background: var(--condition-good-bg);
  color: var(--condition-good-color);
}

.price {
  font-size: 18px;
  font-weight: 700;
  color: var(--price-color);
  margin-left: auto;
}

.shop-footer {
  background: var(--footer-bg);
  border-top: 1px solid var(--card-border);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 16px;
}

.footer-info {
  font-size: 12px;
  color: var(--footer-text);
}

.visit-btn {
  background: var(--btn-bg);
  color: var(--btn-color);
  border: none;
  border-radius: 8px;
  font-size: 13px;
  font-weight: 700;
  padding: 8px 18px;
  cursor: pointer;
}
